#include <bits/stdc++.h>
using namespace std;
const int N=1000005;
int n,p[N],a[N],num[N];
string s;
priority_queue<int> q;
int main()
{
	cin>>n;
	for(int i=1;i<=n;i++)
	{
		s+=")";
		cin>>p[i];
		a[p[i]]=i;
	}
	for(int i=1;i<=n;i+=2)
	{
		q.push(-a[i]);
		num[-q.top()]=1;
		q.pop();
		q.push(-a[i+1]);
	}
	int cnt=0;
	for(int i=1;i<=n;i++)
	{
		if(num[i]==0)
		{
			cnt--;
			if(cnt<0)
			{
				cout<<"NIE";
				return 0;
			}
		}
		else cnt++;
	}
	for(int i=1;i<=n;i++)
	{
		if(num[i]==1) s[p[i]-1]='(';
	}
	cout<<s;
	return 0;
}
